const raw = $input.first().json;

// Erkennen ob Gmail-Pfad (Claude Response) oder Webhook-Pfad (direktes JSON)
let parsed;
if (raw.content && raw.content[0]) {
  // Gmail-Pfad: Claude Response parsen
  try {
    const text = raw.content[0].text.replace(/```json|```/g, '').trim();
    parsed = JSON.parse(text);
  } catch(e) {
    parsed = {};
  }
} else {
  // Webhook-Pfad: Daten direkt nutzen
  parsed = raw;
}

let spamScore = 0;
const gruende = [];

// PLZ ungueltig pruefen
const plz = parsed.plz_wohnort || '';
if (plz === '00000' || plz.toLowerCase().includes('alle')) {
  spamScore += 1;
  gruende.push('PLZ ungueltig');
}

// Verfuegbarkeit extrem pruefen
const verfuegbarkeit = parsed.verfuegbarkeit_stunden_pro_woche || 0;
if (verfuegbarkeit > 80) {
  spamScore += 1;
  gruende.push('Verfuegbarkeit unrealistisch');
}

// Berufserfahrung extrem pruefen
const erfahrung = parsed.berufserfahrung_jahre || 0;
if (erfahrung > 60) {
  spamScore += 1;
  gruende.push('Berufserfahrung unrealistisch');
}

// Name in Grossbuchstaben pruefen
const name = parsed.name || '';
if (name.length > 3 && name === name.toUpperCase()) {
  spamScore += 1;
  gruende.push('Name in Grossbuchstaben');
}

// Motivation zu kurz pruefen
const motivation = parsed.kurzmotivation || '';
if (motivation.length > 0 && motivation.length < 20) {
  spamScore += 1;
  gruende.push('Kurzmotivation zu kurz');
}

// Werbliche Begriffe in Motivation pruefen
const werblich = ['rendite', 'garantie', 'klicken sie', 'einzigartige gelegenheit', 'kaufen'];
if (werblich.some(w => motivation.toLowerCase().includes(w))) {
  spamScore += 2;
  gruende.push('Werbliche Begriffe');
}

const now = new Date().toISOString();

return [{
  json: {
    ...parsed,
    email_from: parsed.email_from || parsed.email || '',
    spam_score: spamScore,
    spam_gruende: gruende,
    ist_spam: spamScore >= 4,
    eingegangen_am: parsed.eingegangen_am || now,
    letzte_aktion: parsed.letzte_aktion || now,
    historie: parsed.historie || JSON.stringify([{action: 'ingested', timestamp: now}])
  }
}];

