const item = $input.first().json;

// Feldnamen normalisieren
item.plz_wohnort = item.plz_wohnort || item.plz || null;
item.vorheriger_beruf = item.vorheriger_beruf || item.beruf || null;

// Fallback: PLZ aus abgedeckte_plz
if (!item.plz_wohnort && item.abgedeckte_plz && item.abgedeckte_plz.length > 0) {
  item.plz_wohnort = item.abgedeckte_plz[0];
}

// Fallback: PLZ aus email_text (nur wenn verfuegbar)
if (!item.plz_wohnort) {
  try {
    const emailText = $('E-Mail Text extrahieren').first().json.email_text || '';
    const plzMatch = emailText.match(/PLZ[:\s]+(\d{5})/i);
    if (plzMatch) item.plz_wohnort = plzMatch[1];
  } catch(e) {
    // Webhook-Pfad: kein E-Mail Text verfuegbar
  }
}

// Pflichtfelder pruefen
const fehlend = [];
if (!item.plz_wohnort) fehlend.push('PLZ Wohnort');
if (!item.verfuegbarkeit_stunden_pro_woche) fehlend.push('Verfuegbarkeit');
if (!item.berufserfahrung_jahre && item.berufserfahrung_jahre !== 0) fehlend.push('Berufserfahrung');

return [{
  json: {
    ...item,
    plz_wohnort: item.plz_wohnort,
    vorheriger_beruf: item.vorheriger_beruf,
    fehlende_felder: fehlend,
    hat_fehlende_felder: fehlend.length > 0
  }
}];

