const email = $input.first().json;

const emailPrompt = 'Du wertest Bewerbungs-E-Mails fuer Objektbesichtiger aus. Extrahiere ALLE Felder als JSON.

REGELN:
- telefon: Telefonnummer. Erkenne auch: Mobil, Handy, Tel, Fon, Mobile, Telefonnummer, Durchwahl
- wohnort: Stadt/Ort des Bewerbers. Erkenne auch: wohne in X, lebe in X, komme aus X, wohnhaft in X
- plz_wohnort: vollstaendige PLZ des Wohnorts als string (z.B. "24103"), NICHT kuerzen
- berufserfahrung_jahre: Zahlen vor Jahre/Jahren
- verfuegbarkeit_stunden_pro_woche: Zahlen vor Stunden/h/Std/Woche
- max_fahrtweg_km: Zahlen vor km/Kilometer/Reichweite
- vorheriger_beruf: Berufsbezeichnung. Erkenne auch: Karriere, Taetigkeit, Job, Position
- iso_zertifizierung: true wenn Ja/yes/vorhanden/zertifiziert
- fuehrerschein: true wenn Ja/yes/vorhanden
- abgedeckte_plz: nur erste 2 Ziffern jeder PLZ als Array, z.B. ["24","23"]
- kurzmotivation: alles nach Motivation: oder letzter Absatz
- Fehlende Werte: null

Gib NUR dieses JSON zurueck ohne Markdown:
{"name":null,"email":null,"telefon":null,"wohnort":null,"plz_wohnort":null,"abgedeckte_plz":[],"max_fahrtweg_km":null,"berufserfahrung_jahre":null,"vorheriger_beruf":null,"verfuegbarkeit_stunden_pro_woche":null,"iso_zertifizierung":false,"fuehrerschein":false,"kurzmotivation":null}

E-Mail:
' + email.email_text;

return [{
  json: {
    email_from: email.email_from,
    email_date: email.email_date,
    claude_body: JSON.stringify({
      model: 'claude-sonnet-4-6',
      max_tokens: 1024,
      messages: [{ role: 'user', content: emailPrompt }]
    })
  }
}];

const item = $('Vollstaendigkeit pruefen').first().json;
const plzResult = $input.first().json;
// PLZ Score
let plzScore = 0;
let plzUnbekannt = false;
let alleVoll = false;
if (!plzResult || plzResult.plz_score === undefined) {
  plzUnbekannt = true;
  plzScore = 0;
} else if (plzResult.plz_score === -1) {
  plzUnbekannt = true;
  plzScore = 0;
} else if (plzResult.plz_score <= 20) {
  alleVoll = true;
  plzScore = plzResult.plz_score;
} else {
  plzScore = plzResult.plz_score;
}
// Verfuegbarkeits-Score (linear: 0h=0, 30h+=100)
const verfuegbarkeit = item.verfuegbarkeit_stunden_pro_woche || 0;
const verfuegbarkeitsScore = Math.min(100, Math.round((verfuegbarkeit / 30) * 100));
// Vollstaendigkeits-Score
const optionaleFelder = ['telefon', 'wohnort', 'max_fahrtweg_km', 'vorheriger_beruf', 'kurzmotivation'];
const ausgefuellt = optionaleFelder.filter(f => item[f] != null && item[f] !== '').length;
const vollstaendigkeitsScore = Math.round((ausgefuellt / optionaleFelder.length) * 100);
// ISO Score
const isoScore = item.iso_zertifizierung ? 100 : 0;
// Gesamtscore
const finalScore = Math.round(
  (plzScore * 0.50) +
  (verfuegbarkeitsScore * 0.25) +
  (vollstaendigkeitsScore * 0.15) +
  (isoScore * 0.10)
);
// Hilfsvariablen fuer Begruendungen
const plzInfo = item.plz_wohnort || 'unbekannt';
const berufsInfo = item.vorheriger_beruf || 'nicht angegeben';
const bedarfInfo = plzResult?.bedarf_status || 'unbekannt';
const besteBereiche = plzResult?.beste_plz_bereiche;
const bedarfText = besteBereiche 
  ? 'Bereich ' + besteBereiche + ': ' + bedarfInfo 
  : bedarfInfo;
const nameInfo = item.name || 'Bewerber:in';
const unbekanntePlzHinweis = plzResult?.unbekannte_plz 
  ? ' Hinweis: PLZ-Bereich(e) ' + plzResult.unbekannte_plz + ' sind zusaetzlich angegeben, aber nicht in der Bedarfskarte erfasst.'
  : '';
// Routing und Begruendung
let finalRouting = 'manuell_pruefen';
let kiEmpfehlung = 'manuell_pruefen';
let kiKonfidenz = 50;
let kiBegruendung = '';
if (alleVoll) {
  finalRouting = 'absage_versendet';
  kiEmpfehlung = 'absagen_region';
  kiKonfidenz = 95;
  kiBegruendung = 'PLZ ' + plzInfo + ' ist laut Bedarfskarte voll besetzt oder nicht gefragt. Kein Bedarf in dieser Region. Empfehle Absage mit Pool-Hinweis.';
} else if (plzUnbekannt) {
  finalRouting = 'manuell_pruefen';
  kiEmpfehlung = 'manuell_pruefen';
  kiKonfidenz = 30;
  kiBegruendung = 'PLZ ' + plzInfo + ' ist nicht in der Bedarfskarte erfasst. Bitte pruefen ob wir dort OBs suchen und die Bedarfskarte ggf. ergaenzen. Dann Bewerbung neu bewerten.';
} else if (verfuegbarkeit < 10) {
  finalRouting = 'manuell_pruefen';
  kiEmpfehlung = 'manuell_pruefen';
  kiKonfidenz = 40;
  kiBegruendung = nameInfo + ' ist nur ' + verfuegbarkeit + 'h/Woche verfuegbar. Unser Minimum sind 10h. Profil sonst: ' + berufsInfo + ', PLZ ' + plzInfo + ' (' + bedarfText + '). Ausnahme sinnvoll?';
} else if (finalScore >= 70 && plzScore >= 70) {
  finalRouting = 'einladung_versendet';
  kiEmpfehlung = 'einladen';
  kiKonfidenz = 85;
  kiBegruendung = 'Guter Match: PLZ ' + plzInfo + ' (' + bedarfText + '), Score ' + finalScore + '/100. Beruf ' + berufsInfo + ' passt, ' + verfuegbarkeit + 'h/Woche verfuegbar. Einladung wurde automatisch versendet.';
} else if (finalScore >= 40) {
  finalRouting = 'manuell_pruefen';
  kiEmpfehlung = 'manuell_pruefen';
  kiKonfidenz = 60;
  kiBegruendung = 'Score ' + finalScore + '/100 — knapp unter Einladungsschwelle (70). ' + bedarfText + '. Beruf: ' + berufsInfo + ', ' + verfuegbarkeit + 'h/Woche. Profil genauer pruefen — Tendenz: einladen wenn Beruf relevant.';
} else {
  finalRouting = 'manuell_pruefen';
  kiEmpfehlung = 'absagen_profil';
  kiKonfidenz = 70;
  kiBegruendung = 'Score ' + finalScore + '/100 — deutlich unter Schwelle. Beruf: ' + berufsInfo + ', nur ' + verfuegbarkeit + 'h/Woche verfuegbar. Empfehle Absage, ausser es gibt besondere Gruende fuer eine Ausnahme.';
}
// Hinweis auf unbekannte Zonen nur fuer manuelle Pruefung (Telegram), nicht fuer Einladungs-Mail
if (finalRouting === 'manuell_pruefen') {
  kiBegruendung = kiBegruendung + unbekanntePlzHinweis;
}
return [{
  json: {
    ...item,
    plz_score: plzScore,
    plz_unbekannt: plzUnbekannt,
    alle_voll: alleVoll,
    verfuegbarkeits_score: verfuegbarkeitsScore,
    vollstaendigkeits_score: vollstaendigkeitsScore,
    iso_score: isoScore,
    final_score: finalScore,
    final_routing: finalRouting,
    ki_empfehlung: kiEmpfehlung,
    ki_konfidenz: kiKonfidenz,
    ki_begruendung: kiBegruendung
  }
}];

const raw = $input.first().json;
const now = new Date().toISOString();

let item;

// Tally Format
const tallyData = raw.body?.data || raw.data;
if (tallyData && tallyData.fields) {
  const fields = tallyData.fields;

  function getFieldByLabel(label) {
    const field = fields.find(f => 
      f.label && f.label.toLowerCase().includes(label.toLowerCase())
    );
    if (!field) return null;
    if (field.type === 'MULTIPLE_CHOICE' && field.options && field.value) {
      const selectedId = Array.isArray(field.value) ? field.value[0] : field.value;
      const option = field.options.find(o => o.id === selectedId);
      return option ? option.text : null;
    }
    if (field.value === null || field.value === undefined) return null;
    return field.value;
  }

  const plzRaw = getFieldByLabel('Abgedeckte PLZ') || '';
  const abgedecktePlz = String(plzRaw)
    .split(/[,\s]+/)
    .map(p => p.trim().substring(0, 2))
    .filter(p => p.length === 2);

  item = {
    externe_id: null, // Tally liefert keine externe ID
    name: getFieldByLabel('Name'),
    email: getFieldByLabel('E-Mail'),
    telefon: getFieldByLabel('Telefon'),
    wohnort: getFieldByLabel('Wohnort'),
    plz_wohnort: getFieldByLabel('PLZ Wohnort'),
    abgedeckte_plz: abgedecktePlz,
    max_fahrtweg_km: getFieldByLabel('Fahrtweg') !== null ? parseInt(getFieldByLabel('Fahrtweg')) : null,
    berufserfahrung_jahre: getFieldByLabel('Berufserfahrung') !== null ? parseInt(getFieldByLabel('Berufserfahrung')) : null,
    vorheriger_beruf: getFieldByLabel('Aktueller Beruf'),
    verfuegbarkeit_stunden_pro_woche: getFieldByLabel('gbarkeit') !== null ? parseInt(getFieldByLabel('gbarkeit')) : null,
    iso_zertifizierung: getFieldByLabel('ISO') === 'Ja',
    fuehrerschein: getFieldByLabel('hrerschein') === 'Ja',
    kurzmotivation: getFieldByLabel('Motivation')
  };

} else {
  // Direktes JSON (curl, Subworkflow)
const body = raw.name ? raw : (raw.body || raw);

  // abgedeckte_plz normalisieren
  let abgedecktePlz = body.abgedeckte_plz;
  if (typeof abgedecktePlz === 'string') {
    abgedecktePlz = abgedecktePlz.split(',').map(p => p.trim().substring(0, 2)).filter(p => p.length === 2);
  } else if (Array.isArray(abgedecktePlz)) {
    abgedecktePlz = abgedecktePlz.map(p => String(p).trim().substring(0, 2));
  } else {
    abgedecktePlz = [];
  }

  item = {
    externe_id: body.externe_id || body.id || null,
    name: body.name,
    email: body.email,
    telefon: body.telefon || null,
    wohnort: body.wohnort || null,
    plz_wohnort: body.plz_wohnort ? String(body.plz_wohnort) : null,
    abgedeckte_plz: abgedecktePlz,
    max_fahrtweg_km: body.max_fahrtweg_km ? parseInt(body.max_fahrtweg_km) : null,
    berufserfahrung_jahre: body.berufserfahrung_jahre ? parseInt(body.berufserfahrung_jahre) : null,
    vorheriger_beruf: body.vorheriger_beruf || null,
    verfuegbarkeit_stunden_pro_woche: body.verfuegbarkeit_stunden_pro_woche ? parseInt(body.verfuegbarkeit_stunden_pro_woche) : null,
    iso_zertifizierung: body.iso_zertifizierung === true || body.iso_zertifizierung === 'true',
    fuehrerschein: body.fuehrerschein === true || body.fuehrerschein === 'true',
    kurzmotivation: body.kurzmotivation || null
  };
}

return [{
  json: {
    ...item,
    email_from: item.email || '',
    eingegangen_am: now,
    letzte_aktion: now,
    historie: JSON.stringify([{action: 'webhook_ingested', timestamp: now}])
  }
}];

