(() => {

const fehlendeFelder = $('Vollstaendigkeit pruefen').first().json.hat_fehlende_felder;
const plzScore = $input.first().json.plz_score;
const unbekanntePlz = $input.first().json.unbekannte_plz;
const abgedeckteVorhanden = $('Vollstaendigkeit pruefen').first().json.abgedeckte_plz?.length > 0;

// 1. PLZ komplett unbekannt, weil gar keine abgedeckte_plz angegeben wurde
//    -> Datenproblem beim Bewerber -> Rueckfrage (PLZ gehoert zu den nachzufragenden Punkten)
if (plzScore === -1 && !abgedeckteVorhanden) {
  return 0; // Rueckfrage
}

// 2. PLZ komplett unbekannt, obwohl abgedeckte_plz angegeben wurde
//    -> keine davon ist in der Bedarfskarte -> internes Problem -> Grenzfall
if (plzScore === -1) {
  return 1; // Grenzfall/Telegram
}

// 3. PLZ schlecht (<=20) UND es gibt zusaetzlich unbekannte Zonen
//    -> nicht automatisch absagen, da unbekannte Zone evtl. Bedarf hat -> manuelle Pruefung
if (plzScore <= 20 && unbekanntePlz) {
  return 1; // Grenzfall mit Hinweis auf unbekannte Zone
}

// 4. PLZ schlecht, alle Zonen bekannt -> direkte Absage (Prioritaet vor fehlenden Feldern)
if (plzScore <= 20) {
  return 3;
}

// 5. PLZ gut, aber Pflichtfelder fehlen -> Rueckfrage
if (fehlendeFelder) {
  return 0;
}

// 6. Alles gut -> Scoring
return 2;

})()
}}

