const item = $('Vollstaendigkeit pruefen').first().json;
const input = $input.first().json;
const hatScoring = input.final_score !== undefined;

const finalScore = hatScoring ? input.final_score : null;
const kiEmpfehlung = hatScoring ? input.ki_empfehlung : 'manuell_pruefen';

let kiBegruendung;
if (hatScoring) {
  kiBegruendung = input.ki_begruendung;
} else if (input.plz_score === -1) {
  // Komplett unbekannt: keine der angegebenen PLZ ist in der Bedarfskarte
  kiBegruendung = 'PLZ ' + (item.plz_wohnort || 'unbekannt') + ' mit Fokus auf Raum ' + (item.abgedeckte_plz?.join(', ') || 'unbekannt') + ' ist nicht in der Bedarfskarte erfasst. Bitte pruefen ob wir dort OBs suchen und Bedarfskarte ggf. ergaenzen.';
} else {
  // PLZ bekannt aber schlecht (<=20), zusaetzlich gibt es unbekannte Zonen
  const besteBereiche = input.beste_plz_bereiche;
  const unbekanntHinweis = input.unbekannte_plz 
    ? ' Zusaetzlich sind PLZ-Bereich(e) ' + input.unbekannte_plz + ' nicht in der Bedarfskarte erfasst.' 
    : '';
  kiBegruendung = 'PLZ ' + (item.plz_wohnort || 'unbekannt') + ' (Bereich ' + (besteBereiche || '?') + ') ist laut Bedarfskarte ' + (input.bedarf_status || 'unbekannt') + '.' + unbekanntHinweis + ' Vor einer Absage bitte pruefen ob in den unbekannten Zonen Bedarf besteht.';
}

return [{
  json: {
    ...item,
    final_score: finalScore,
    ki_empfehlung: kiEmpfehlung,
    ki_begruendung: kiBegruendung
  }
}];
